
        SELECT union_id, emp_id AS qw_emp_id, anyLast(emp_name) AS qw_emp_name,
               anyLast(company) AS qw_company, anyLast(belong_name) AS qw_belong_name,
               anyLast(external_user_id) AS external_user_id, min(add_time) AS first_add_time,
               max(add_time) AS latest_add_time, max(qw_tag_name) AS qw_tag_name, max(emp_remark) AS emp_remark,
               minIf(del_time, del_time > toDateTime('1971-01-01 00:00:00')) AS first_del_time,
               max(del_time IS NULL OR del_time <= toDateTime('1971-01-01 00:00:00')) AS is_current_friend
